public static boolean isRailCarValidationEnabled()
{
    ETGCanadaParameters etgParams = ETGCanadaParameters::find();

    return etgParams
        && etgParams.EnableRailCarSerialNumValidation == NoYes::Yes;
}

public static boolean isClearingDateReconciliationEnabled()
{
    ETGCanadaParameters etgParams = ETGCanadaParameters::find();

    return etgParams
        && etgParams.EnableClearingDateReconciliation == NoYes::Yes;
}
